        tree = new long[rows + 1][cols + 1];
    }

    public void update(int r, int c, long val) {
        for (int i = r + 1; i <= rows; i += i & (-i))
            for (int j = c + 1; j <= cols; j += j & (-j))
                tree[i][j] += val;
    }

